/**
 * Tests for Canvas Snap, Guides & Alignment System
 * Feature #60
 */

import {
  snapToGrid,
  snapPointToGrid,
  calculateSnap,
  alignElements,
  distributeElements,
  generateGridLines,
  DEFAULT_SNAP_CONFIG,
} from '@lib/editor/snap-guides';
import type { Rect, SnapConfig } from '@lib/editor/snap-guides';

// ============================================================
// snapToGrid
// ============================================================
describe('snapToGrid', () => {
  it('should snap to nearest grid line', () => {
    expect(snapToGrid(13, 8)).toBe(16);
    expect(snapToGrid(3, 8)).toBe(0);
    expect(snapToGrid(4, 8)).toBe(8); // Math.round(0.5) = 1 in JS
    expect(snapToGrid(5, 8)).toBe(8);
  });

  it('should return exact value when already on grid', () => {
    expect(snapToGrid(16, 8)).toBe(16);
    expect(snapToGrid(0, 8)).toBe(0);
    expect(snapToGrid(64, 16)).toBe(64);
  });

  it('should return value unchanged when gridSize is 0', () => {
    expect(snapToGrid(13, 0)).toBe(13);
    expect(snapToGrid(100, 0)).toBe(100);
  });

  it('should handle negative values', () => {
    expect(snapToGrid(-3, 8)).toEqual(0); // -0 equals 0 with toEqual
    expect(snapToGrid(-5, 8)).toBe(-8);
  });

  it('should work with various grid sizes', () => {
    expect(snapToGrid(7, 4)).toBe(8);
    expect(snapToGrid(15, 16)).toBe(16);
    expect(snapToGrid(25, 10)).toBe(30);
    expect(snapToGrid(24, 10)).toBe(20);
  });
});

