// ============================================================
// calculateSnap — grid snap
// ============================================================
describe('calculateSnap - grid', () => {
  const gridOnlyConfig: SnapConfig = {
    ...DEFAULT_SNAP_CONFIG,
    snapToGrid: true,
    snapToElements: false,
    snapToCanvas: false,
    gridSize: 16,
    snapThreshold: 5,
  };

  it('should snap to grid when within threshold', () => {
    const rect: Rect = { x: 33, y: 65, width: 100, height: 50 };
    const result = calculateSnap(rect, [], gridOnlyConfig);
    expect(result.snappedX).toBe(32); // nearest 16 grid
    expect(result.snappedY).toBe(64);
  });

  it('should not snap when outside threshold', () => {
    const rect: Rect = { x: 40, y: 72, width: 100, height: 50 };
    // 40 is exactly on grid (16*2.5=40), 72 is exactly on grid (16*4.5=72)
    // Actually 40/16 = 2.5, round to 2*16=32 or 3*16=48 -> nearest is 40 (diff 0)
    // Actually round(40/16)*16 = round(2.5)*16 = 2*16 = 32? No, Math.round(2.5)=3 actually
    // Let me recalculate: Math.round(40/16)*16 = Math.round(2.5)*16 = 3*16 = 48
    // diff = |48-40| = 8 > 5 (threshold), so no snap
    const result = calculateSnap(rect, [], gridOnlyConfig);
    expect(result.snappedX).toBe(40); // not snapped (diff > threshold)
  });

  it('should not snap when grid disabled', () => {
    const noGridConfig: SnapConfig = { ...gridOnlyConfig, snapToGrid: false };
    const rect: Rect = { x: 33, y: 65, width: 100, height: 50 };
    const result = calculateSnap(rect, [], noGridConfig);
    expect(result.snappedX).toBe(33);
    expect(result.snappedY).toBe(65);
  });
});

// ============================================================
// calculateSnap — canvas snap
// ============================================================
describe('calculateSnap - canvas', () => {
  const canvasConfig: SnapConfig = {
    ...DEFAULT_SNAP_CONFIG,
    snapToGrid: false,
    snapToElements: false,
    snapToCanvas: true,
    canvasWidth: 1920,
    canvasHeight: 1080,
    snapThreshold: 5,
  };

  it('should snap to canvas left edge', () => {
    const rect: Rect = { x: 3, y: 200, width: 100, height: 50 };
    const result = calculateSnap(rect, [], canvasConfig);
    expect(result.snappedX).toBe(0);
    expect(result.guides.some(g => g.type === 'vertical' && g.position === 0)).toBe(true);
  });

  it('should snap to canvas center', () => {
    const rect: Rect = { x: 958, y: 200, width: 100, height: 50 };
    // center of rect = 958 + 50 = 1008, canvas center = 960
    // diff = |1008 - 960| = 48 > 5, so no center snap
    // But left edge: 958 vs 960 (canvas center), diff = 2 < 5 → snap
    const result = calculateSnap(rect, [], canvasConfig);
    expect(result.snappedX).toBe(960);
    expect(result.guides.some(g => g.type === 'vertical' && g.position === 960)).toBe(true);
  });

  it('should snap to canvas top edge', () => {
    const rect: Rect = { x: 200, y: 2, width: 100, height: 50 };
    const result = calculateSnap(rect, [], canvasConfig);
    expect(result.snappedY).toBe(0);
    expect(result.guides.some(g => g.type === 'horizontal' && g.position === 0)).toBe(true);
  });

  it('should produce no guides when far from edges', () => {
    const rect: Rect = { x: 500, y: 400, width: 100, height: 50 };
    const result = calculateSnap(rect, [], canvasConfig);
    expect(result.guides.length).toBe(0);
  });
});

// ============================================================
// calculateSnap — element snap
// ============================================================
describe('calculateSnap - elements', () => {
  const elemConfig: SnapConfig = {
    ...DEFAULT_SNAP_CONFIG,
    snapToGrid: false,
    snapToCanvas: false,
    snapToElements: true,
    snapThreshold: 5,
  };

  it('should snap to another element left edge', () => {
    const moving: Rect = { x: 102, y: 200, width: 50, height: 50 };
    const other: Rect = { x: 100, y: 50, width: 80, height: 40 };
    const result = calculateSnap(moving, [other], elemConfig);
    expect(result.snappedX).toBe(100);
    expect(result.guides.some(g => g.type === 'vertical')).toBe(true);
  });

  it('should snap to another element center', () => {
    // Other center X = 100 + 80/2 = 140
    // Moving center X = 138 + 50/2 = 163, diff from 140 = 23 → too far
    // Moving left X = 138, diff from 140 = 2 → would snap left edge
    // But we want center snap: movingCenterX = x + 25. 
    // If we want movingCenter=140, then x = 140-25 = 115
    // So moving at x=113, center=138, diff from 140 = 2 → snap
    const moving: Rect = { x: 113, y: 200, width: 50, height: 50 };
    const other: Rect = { x: 100, y: 50, width: 80, height: 40 };
    // Moving center X = 113 + 25 = 138
    // Other center X = 100 + 40 = 140
    // diff = |138 - 140| = 2 < 5 → snap to center
    const result = calculateSnap(moving, [other], elemConfig);
    expect(result.snappedX).toBe(115); // adjusted so center = 140
  });

  it('should produce horizontal guide for Y alignment', () => {
    const moving: Rect = { x: 300, y: 52, width: 50, height: 50 };
    const other: Rect = { x: 100, y: 50, width: 80, height: 40 };
    const result = calculateSnap(moving, [other], elemConfig);
    expect(result.snappedY).toBe(50);
    expect(result.guides.some(g => g.type === 'horizontal')).toBe(true);
  });

  it('should handle empty other rects', () => {
    const moving: Rect = { x: 100, y: 100, width: 50, height: 50 };
    const result = calculateSnap(moving, [], elemConfig);
    expect(result.snappedX).toBe(100);
    expect(result.snappedY).toBe(100);
    expect(result.guides.length).toBe(0);
  });
});

// ============================================================
// alignElements
// ============================================================
describe('alignElements', () => {
  const rects: Rect[] = [
    { x: 10, y: 20, width: 100, height: 50 },
    { x: 50, y: 80, width: 80, height: 60 },
    { x: 200, y: 40, width: 120, height: 30 },
  ];

  it('should align left', () => {
    const result = alignElements(rects, 'left');
    result.forEach(r => expect(r.x).toBe(10));
  });

  it('should align right', () => {
    const result = alignElements(rects, 'right');
    // maxRight = max(110, 130, 320) = 320
    expect(result[0].x).toBe(220); // 320 - 100
    expect(result[1].x).toBe(240); // 320 - 80
    expect(result[2].x).toBe(200); // 320 - 120
  });

  it('should align top', () => {
    const result = alignElements(rects, 'top');
    result.forEach(r => expect(r.y).toBe(20));
  });

  it('should align bottom', () => {
    const result = alignElements(rects, 'bottom');
    // maxBottom = max(70, 140, 70) = 140
    expect(result[0].y).toBe(90);  // 140 - 50
    expect(result[1].y).toBe(80);  // 140 - 60
    expect(result[2].y).toBe(110); // 140 - 30
  });

  it('should center horizontally on canvas', () => {
    const result = alignElements(rects, 'center-h', 1920);
    expect(result[0].x).toBe((1920 - 100) / 2);
    expect(result[1].x).toBe((1920 - 80) / 2);
    expect(result[2].x).toBe((1920 - 120) / 2);
  });

  it('should center horizontally on bounding box when no canvas', () => {
    const result = alignElements(rects, 'center-h');
    // bboxCenter = (10 + 320) / 2 = 165
    expect(result[0].x).toBe(165 - 50);  // 115
    expect(result[1].x).toBe(165 - 40);  // 125
    expect(result[2].x).toBe(165 - 60);  // 105
  });

  it('should center vertically on canvas', () => {
    const result = alignElements(rects, 'center-v', undefined, 1080);
    expect(result[0].y).toBe((1080 - 50) / 2);
    expect(result[1].y).toBe((1080 - 60) / 2);
    expect(result[2].y).toBe((1080 - 30) / 2);
  });

  it('should return empty array for empty input', () => {
    expect(alignElements([], 'left')).toEqual([]);
  });

  it('should preserve width and height', () => {
    const result = alignElements(rects, 'left');
    result.forEach((r, i) => {
      expect(r.width).toBe(rects[i].width);
      expect(r.height).toBe(rects[i].height);
    });
  });
});

// ============================================================
// distributeElements
// ============================================================
describe('distributeElements', () => {
  it('should distribute horizontally with equal gaps', () => {
    const rects: Rect[] = [
      { x: 0, y: 0, width: 50, height: 50 },
      { x: 300, y: 0, width: 50, height: 50 },
      { x: 100, y: 0, width: 50, height: 50 },
    ];
    const result = distributeElements(rects, 'horizontal');
    // sorted by x: [0,50], [100,50], [300,50]
    // totalSpace = (300 + 50) - 0 - 150 = 200
    // gap = 200 / 2 = 100
    expect(result[0].x).toBe(0);
    expect(result[1].x).toBe(150); // 0 + 50 + 100
    expect(result[2].x).toBe(300); // 150 + 50 + 100
  });

  it('should distribute vertically with equal gaps', () => {
    const rects: Rect[] = [
      { x: 0, y: 0, width: 50, height: 40 },
      { x: 0, y: 200, width: 50, height: 40 },
      { x: 0, y: 100, width: 50, height: 40 },
    ];
    const result = distributeElements(rects, 'vertical');
    // sorted by y: [0,40], [100,40], [200,40]
    // totalSpace = (200+40) - 0 - 120 = 120
    // gap = 120 / 2 = 60
    expect(result[0].y).toBe(0);
    expect(result[1].y).toBe(100); // 0 + 40 + 60
    expect(result[2].y).toBe(200); // 100 + 40 + 60
  });

  it('should return original rects if less than 3', () => {
    const rects: Rect[] = [
      { x: 0, y: 0, width: 50, height: 50 },
      { x: 200, y: 0, width: 50, height: 50 },
    ];
    const result = distributeElements(rects, 'horizontal');
    expect(result).toEqual(rects);
  });

  it('should handle 1 element', () => {
    const rects: Rect[] = [{ x: 50, y: 50, width: 100, height: 100 }];
    const result = distributeElements(rects, 'horizontal');
    expect(result).toEqual(rects);
  });

  it('should preserve sizes', () => {
    const rects: Rect[] = [
      { x: 0, y: 0, width: 60, height: 30 },
      { x: 200, y: 0, width: 40, height: 30 },
      { x: 100, y: 0, width: 80, height: 30 },
    ];
    const result = distributeElements(rects, 'horizontal');
    // All widths preserved
    expect(result.map(r => r.width).sort()).toEqual([40, 60, 80]);
  });
});

// ============================================================
// generateGridLines
// ============================================================
describe('generateGridLines', () => {
  it('should generate grid lines', () => {
    const lines = generateGridLines(160, 80, 16);
    expect(lines.length).toBeGreaterThan(0);

    const verticals = lines.filter(l => l.type === 'vertical');
    const horizontals = lines.filter(l => l.type === 'horizontal');

    // 0, 16, 32, 48, 64, 80, 96, 112, 128, 144, 160 = 11 vertical lines
    expect(verticals.length).toBe(11);
    // 0, 16, 32, 48, 64, 80 = 6 horizontal lines
    expect(horizontals.length).toBe(6);
  });

  it('should mark major lines correctly', () => {
    const lines = generateGridLines(160, 80, 16, 4);
    const majors = lines.filter(l => l.isMajor);
    // Major at every 4th line: 0, 64, 128 for vertical (3) + 0, 64 for horizontal (2)
    // 0/16=0 (mod 4=0 ✓), 64/16=4 (mod 4=0 ✓), 128/16=8 (mod 4=0 ✓)
    // Verticals: 0, 64, 128 = 3 major
    // Horizontals: 0, 64 = 2 major
    expect(majors.length).toBe(5);
  });

  it('should return empty when gridSize is 0', () => {
    expect(generateGridLines(1920, 1080, 0)).toEqual([]);
  });

  it('should return empty when gridSize is negative', () => {
    expect(generateGridLines(1920, 1080, -8)).toEqual([]);
  });
});

